const { BigQuery } = require('@google-cloud/bigquery');
const crypto = require('crypto');

const MAX_QUERY_SIZE = 1000000;
const MAX_DATASET_LENGTH = 100;
const MAX_TABLE_LENGTH = 100;
const ALLOWED_AGGREGATION_FUNCTIONS = ['SUM', 'AVG', 'COUNT', 'MAX', 'MIN'];
const QUERY_TIMEOUT_MS = 500000;

const bigquery = new BigQuery();

function validateInput(input) {
  if (!input || typeof input !== 'object') {
    throw new Error('Invalid input: must be an object');
  }

  const { projectId, datasetId, tableId, aggregationField, aggregationFunction, groupByField, filters } = input;

  if (!projectId || typeof projectId !== 'string' || !/^[a-z][a-z0-9-]{4,28}[a-z0-9]$/.test(projectId)) {
    throw new Error('Invalid projectId format');
  }

  if (!datasetId || typeof datasetId !== 'string' || datasetId.length > MAX_DATASET_LENGTH || !/^[a-zA-Z0-9_]+$/.test(datasetId)) {
    throw new Error('Invalid datasetId format');
  }

  if (!tableId || typeof tableId !== 'string' || tableId.length > MAX_TABLE_LENGTH || !/^[a-zA-Z0-9_]+$/.test(tableId)) {
    throw new Error('Invalid tableId format');
  }

  if (!aggregationField || typeof aggregationField !== 'string' || !/^[a-zA-Z0-9_]+$/.test(aggregationField)) {
    throw new Error('Invalid aggregationField format');
  }

  if (!aggregationFunction || !ALLOWED_AGGREGATION_FUNCTIONS.includes(aggregationFunction.toUpperCase())) {
    throw new Error('Invalid aggregationFunction: must be one of ' + ALLOWED_AGGREGATION_FUNCTIONS.join(', '));
  }

  if (groupByField && (typeof groupByField !== 'string' || !/^[a-zA-Z0-9_]+$/.test(groupByField))) {
    throw new Error('Invalid groupByField format');
  }

  if (filters && !Array.isArray(filters)) {
    throw new Error('Filters must be an array');
  }

  if (filters) {
    for (const filter of filters) {
      if (!filter.field || typeof filter.field !== 'string' || !/^[a-zA-Z0-9_]+$/.test(filter.field)) {
        throw new Error('Invalid filter field format');
      }
      if (!filter.operator || !['=', '>', '<', '>=', '<=', '!=', 'IN', 'NOT IN'].includes(filter.operator)) {
        throw new Error('Invalid filter operator');
      }
      if (filter.value === undefined || filter.value === null) {
        throw new Error('Filter value is required');
      }
    }
  }

  return { projectId, datasetId, tableId, aggregationField, aggregationFunction, groupByField, filters };
}

function sanitizeIdentifier(identifier) {
  return identifier.replace(/[^a-zA-Z0-9_]/g, '');
}

function buildSecureQuery(params) {
  const { projectId, datasetId, tableId, aggregationField, aggregationFunction, groupByField, filters } = params;

  const safeProjectId = sanitizeIdentifier(projectId);
  const safeDatasetId = sanitizeIdentifier(datasetId);
  const safeTableId = sanitizeIdentifier(tableId);
  const safeAggField = sanitizeIdentifier(aggregationField);
  const safeGroupBy = groupByField ? sanitizeIdentifier(groupByField) : null;

  let query = `SELECT `;
  
  if (safeGroupBy) {
    query += `\`${safeGroupBy}\`, `;
  }
  
  query += `${aggregationFunction.toUpperCase()}(\`${safeAggField}\`) as aggregated_value `;
  query += `FROM \`${safeProjectId}.${safeDatasetId}.${safeTableId}\` `;

  const queryParams = [];
  
  if (filters && filters.length > 0) {
    query += 'WHERE ';
    const conditions = [];
    
    filters.forEach((filter, index) => {
      const safeField = sanitizeIdentifier(filter.field);
      
      if (filter.operator === 'IN' || filter.operator === 'NOT IN') {
        if (!Array.isArray(filter.value)) {
          throw new Error('IN/NOT IN operator requires array value');
        }
        const paramNames = filter.value.map((_, i) => `@param${queryParams.length + i}`);
        filter.value.forEach(val => queryParams.push(val));
        conditions.push(`\`${safeField}\` ${filter.operator} (${paramNames.join(', ')})`);
      } else {
        conditions.push(`\`${safeField}\` ${filter.operator} @param${queryParams.length}`);
        queryParams.push(filter.value);
      }
    });
    
    query += conditions.join(' AND ');
  }

  if (safeGroupBy) {
    query += ` GROUP BY \`${safeGroupBy}\``;
  }

  query += ' ORDER BY aggregated_value DESC';

  return { query, queryParams };
}

async function executeQuery(query, params) {
  const options = {
    query: query,
    params: params,
    timeoutMs: QUERY_TIMEOUT_MS,
    maximumBytesBilled: '10000000000',
    useLegacySql: false,
  };

  const [job] = await bigquery.createQueryJob(options);
  
  const [rows] = await job.getQueryResults({
    maxResults: MAX_QUERY_SIZE,
  });

  return rows;
}

function sanitizeOutput(data) {
  if (!Array.isArray(data)) {
    return [];
  }

  return data.map(row => {
    const sanitized = {};
    for (const [key, value] of Object.entries(row)) {
      if (typeof value === 'string' && value.length > 10000) {
        sanitized[key] = value.substring(0, 10000);
      } else {
        sanitized[key] = value;
      }
    }
    return sanitized;
  });
}

exports.processBigData = async (req, res) => {
  const requestId = crypto.randomBytes(16).toString('hex');
  
  res.set('X-Content-Type-Options', 'nosniff');
  res.set('X-Frame-Options', 'DENY');
  res.set('Content-Security-Policy', "default-src 'none'");
  res.set('X-Request-ID', requestId);

  try {
    if (req.method !== 'POST') {
      res.status(405).json({ error: 'Method not allowed' });
      return;
    }

    const authHeader = req.get('Authorization');
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      res.status(401).json({ error: 'Unauthorized: Missing or invalid authorization header' });
      return;
    }

    const validatedInput = validateInput(req.body);
    
    const { query, queryParams } = buildSecureQuery(validatedInput);
    
    console.log(`[${requestId}] Processing query for dataset: ${validatedInput.datasetId}.${validatedInput.tableId}`);
    
    const results = await executeQuery(query, queryParams);
    
    const sanitizedResults = sanitizeOutput(results);
    
    console.log(`[${requestId}] Successfully processed ${sanitizedResults.length} rows`);
    
    res.status(200).json({
      success: true,
      requestId: requestId,
      rowCount: sanitizedResults.length,
      data: sanitizedResults,
      metadata: {
        aggregationFunction: validatedInput.aggregationFunction,
        aggregationField: validatedInput.aggregationField,
        groupByField: validatedInput.groupByField || null
      }
    });

  } catch (error) {
    console.error(`[${requestId}] Error processing request:`, error.message);
    
    const statusCode = error.message.includes('Invalid') || error.message.includes('Unauthorized') ? 400 : 500;
    
    res.status(statusCode).json({
      success: false,
      requestId: requestId,
      error: 'Processing failed',
      message: error.message
    });
  }
};